Here's the XAML and ViewModel you need:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="Auto,*">
                    <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found." HorizontalOptions="Center" VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

### ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool isRefreshing;

    [ObservableProperty]
    private Item? currentItem;

    public ObservableCollection<Item> Items { get; } = new();

    [RelayCommand]
    private async Task Refresh()
    {
        var data = await _api.GetItemsAsync();
        MainThread.BeginInvokeOnMainThread(() =>
        {
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        });
        IsRefreshing = false;  // stops the spinner
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;
        await _nav.GoToAsync(nameof(DetailPage), new Dictionary<string, object>
        {
            { "Item", CurrentItem }
        });
        CurrentItem = null;  // reset so the same item can be re-selected
    }
}
```

### Key bindings explained

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `IsRefreshing` | `bool IsRefreshing` | Two-way; set `false` when load completes to stop spinner |
| `Command` (RefreshView) | `RefreshCommand` | Fires on pull-down; calls your API |
| `SelectedItem` | `Item? CurrentItem` | Two-way; holds the tapped item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap; triggers navigation |
| `ItemsSource` | `ObservableCollection<Item>` | Must be `ObservableCollection`, not `List`, so UI auto-updates |

**Important notes:**
- Set `CurrentItem = null` after navigating so the user can re-select the same item.
- Always set `IsRefreshing = false` when the refresh finishes.
- Use `x:DataType` on the `DataTemplate` for compiled bindings.
- Wrap the `EmptyView` in a `ContentView` for custom empty states.
